  BarChart2, Gift, Award, Settings, LogOut, ChevronDown, ChevronRight,
  Menu, Bell, Leaf
} from 'lucide-react';

const NAV = [
  { label: 'Dashboard', icon: LayoutDashboard, path: '/dashboard' },
  {
    label: 'Content', icon: FileText, children: [
      { label: 'Articles', path: '/content/articles', icon: FileText },
      { label: 'Meditation', path: '/content/meditation', icon: Music },
      { label: 'Categories', path: '/content/categories', icon: Tag },
    ]
  },
  {
    label: 'Monitoring', icon: BarChart2, children: [
      { label: 'Counsellors', path: '/monitoring/counsellors', icon: Users },
      { label: 'Chatbot', path: '/monitoring/chatbot', icon: MessageSquare },
      { label: 'Content Reports', path: '/monitoring/content', icon: BarChart2 },
    ]
  },
  {
    label: 'Gamification', icon: Gift, children: [
      { label: 'Vouchers', path: '/gamification/vouchers', icon: Gift },
      { label: 'Rewards', path: '/gamification/rewards', icon: Award },
    ]
  },
  { label: 'Account', icon: Settings, path: '/account' },
];

const S = {
  sidebar: (collapsed) => ({
    width: collapsed ? '64px' : '240px',
    minWidth: collapsed ? '64px' : '240px',
    background: 'white',
    borderRight: '1px solid #E5E4E0',
    display: 'flex',
    flexDirection: 'column',
    transition: 'width 0.25s ease',
    overflow: 'hidden',
  }),
  logoBox: {
    display: 'flex', alignItems: 'center', gap: '12px',
    padding: '20px 16px', borderBottom: '1px solid #E5E4E0',
  },
  logoIcon: {
    width: '32px', height: '32px', borderRadius: '10px',
    background: '#7C9C84', display: 'flex', alignItems: 'center',
    justifyContent: 'center', flexShrink: 0,
  },
  logoText: {
    fontFamily: '"Playfair Display", serif', fontWeight: 600,
    fontSize: '15px', color: '#333', lineHeight: '1.3',
  },
  logoSub: { fontFamily: 'Outfit, sans-serif', fontSize: '11px', fontWeight: 400, color: '#888' },
  nav: { flex: 1, overflowY: 'auto', padding: '12px 8px', display: 'flex', flexDirection: 'column', gap: '2px' },
  navGroup: (isActive) => ({
    display: 'flex', alignItems: 'center', gap: '12px',
    padding: '10px 16px', borderRadius: '12px',
    fontSize: '14px', fontFamily: 'Outfit, sans-serif', fontWeight: isActive ? 600 : 500,
    color: isActive ? '#7C9C84' : '#555',
    background: isActive ? '#E5EDE8' : 'transparent',
    cursor: 'pointer', border: 'none', width: '100%', transition: 'all 0.15s',
    textDecoration: 'none',
  }),
  subNav: { marginLeft: '28px', paddingLeft: '12px', borderLeft: '2px solid #E5EDE8', display: 'flex', flexDirection: 'column', gap: '2px' },
  subLink: (isActive) => ({
    display: 'flex', alignItems: 'center', gap: '8px',
    padding: '8px 12px', borderRadius: '10px',
    fontSize: '13px', fontFamily: 'Outfit, sans-serif', fontWeight: isActive ? 600 : 400,
    color: isActive ? '#7C9C84' : '#777',
    background: isActive ? '#E5EDE8' : 'transparent',
    cursor: 'pointer', textDecoration: 'none', transition: 'all 0.15s',
  }),
  topbar: {
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '14px 24px', background: 'white', borderBottom: '1px solid #E5E4E0', flexShrink: 0,
  },
  topbarTitle: { fontFamily: '"Playfair Display", serif', fontWeight: 600, fontSize: '18px', color: '#333' },
  avatar: {
    width: '32px', height: '32px', borderRadius: '50%',
    background: '#BBCBC2', display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: '#7C9C84', fontFamily: 'Outfit, sans-serif', fontWeight: 700, fontSize: '14px',
  },
};

function SidebarGroup({ item, collapsed }) {
  const [open, setOpen] = useState(true);
  if (!item.children) {
    return (
      <NavLink to={item.path} style={({ isActive }) => S.navGroup(isActive)}>
        <item.icon size={17} style={{ flexShrink: 0 }} />
        {!collapsed && item.label}
      </NavLink>
    );
  }
  return (
    <div>
      <button onClick={() => setOpen(o => !o)} style={S.navGroup(false)}>
        <span style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <item.icon size={17} style={{ flexShrink: 0 }} />
          {!collapsed && item.label}
        </span>
        {!collapsed && (open ? <ChevronDown size={13} /> : <ChevronRight size={13} />)}
      </button>
      {open && !collapsed && (
        <div style={S.subNav}>
          {item.children.map(c => (
            <NavLink key={c.path} to={c.path} style={({ isActive }) => S.subLink(isActive)}>
              <c.icon size={13} /> {c.label}
            </NavLink>
          ))}
        </div>
      )}
    </div>
  );
}

export default function AdminLayout({ children, onLogout }) {
  const [collapsed, setCollapsed] = useState(false);

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: '#F6F5F2' }}>
      {/* Sidebar */}
      <aside style={S.sidebar(collapsed)}>
        <div style={S.logoBox}>
          <div style={S.logoIcon}><Leaf size={16} color="white" /></div>
          {!collapsed && (
            <span style={S.logoText}>
              MindSpace<br /><span style={S.logoSub}>Admin</span>
            </span>
          )}
        </div>
        <nav style={S.nav}>
          {NAV.map(item => <SidebarGroup key={item.label} item={item} collapsed={collapsed} />)}
        </nav>
        <div style={{ padding: '8px 8px 16px' }}>
          <button
            onClick={() => setCollapsed(c => !c)}
            style={{ ...S.navGroup(false), justifyContent: 'center' }}
          >
            <Menu size={16} />
            {!collapsed && <span style={{ fontSize: '12px' }}>Collapse</span>}
          </button>
        </div>
      </aside>

      {/* Main */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <header style={S.topbar}>
          <span style={S.topbarTitle}>Admin Portal</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <button style={{ position: 'relative', padding: '8px', border: 'none', background: 'transparent', cursor: 'pointer', borderRadius: '10px' }}>
              <Bell size={18} color="#888" />
              <span style={{ position: 'absolute', top: '8px', right: '8px', width: '8px', height: '8px', background: '#f87171', borderRadius: '50%' }} />
            </button>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', paddingLeft: '12px', borderLeft: '1px solid #E5E4E0' }}>
              <div style={S.avatar}>A</div>
              <span style={{ fontFamily: 'Outfit, sans-serif', fontSize: '14px', fontWeight: 500, color: '#333' }}>Admin</span>
              <button onClick={onLogout} style={{ padding: '6px', border: 'none', background: 'transparent', cursor: 'pointer', borderRadius: '8px' }}>
                <LogOut size={15} color="#888" />
              </button>
            </div>
          </div>
        </header>
        <main style={{ flex: 1, overflowY: 'auto', padding: '24px' }}>
          {children}
        </main>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { collection, getDocs, onSnapshot, query, orderBy, limit, where } from 'firebase/firestore';
import { db } from '../firebase';

/**
 * Generic hook: subscribe to a Firestore collection in real-time.
 * @param {string} col - Collection name
 * @param {Array}  constraints - Optional Firestore query constraints
 */
export function useCollection(col, constraints = []) {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const q = query(collection(db, col), ...constraints);
    const unsub = onSnapshot(
      q,
      (snap) => {
        setData(snap.docs.map(d => ({ id: d.id, ...d.data() })));
        setLoading(false);
      },
      (err) => { setError(err.message); setLoading(false); }
    );
    return () => unsub();
  }, [col]);

  return { data, loading, error };
}

/**
 * Hook: fetch all users (collection: 'users')
 */
export function useUsers() {
  return useCollection('users');
}

/**
 * Hook: fetch counsellor applications (collection: 'counsellor_applications')
